# Valeur par défaut
def saluer(nom, message='Bonjour'):
    print(f'{message}, {nom} !')

saluer('Alice')            # Bonjour, Alice !
saluer('Bob', 'Bonsoir')   # Bonsoir, Bob !

# *args : nombre variable d'arguments
def somme(*nombres):
    return sum(nombres)

print(somme(1, 2, 3, 4))  # 10

# **kwargs : arguments nommés variables
def afficher_infos(**infos):
    for cle, val in infos.items():
        print(f'{cle} : {val}')

afficher_infos(nom='Alice', age=30)

# enumerate : index + valeur
for i, fruit in enumerate(['pomme', 'banane']):
    print(f'{i}: {fruit}')  # 0: pomme, 1: banane

# zip : parcourir deux listes ensemble
noms = ['Alice', 'Bob']
ages = [30, 25]
for nom, age in zip(noms, ages):
    print(f'{nom} a {age} ans')

# break : arrêter la boucle
for i in range(10):
    if i == 5:
        break
    print(i)  # 0, 1, 2, 3, 4

# continue : passer à l'itération suivante
for i in range(5):
    if i == 2:
        continue
    print(i)  # 0, 1, 3, 4

# Dict comprehension
carres = {x: x**2 for x in range(6)}
print(carres)  # {0:0, 1:1, 2:4, 3:9, 4:16, 5:25}

# Inverser clés/valeurs
orig = {'a': 1, 'b': 2, 'c': 3}
inverse = {v: k for k, v in orig.items()}

# defaultdict — valeur par défaut automatique
from collections import defaultdict
compteur = defaultdict(int)
for lettre in 'mississippi':
    compteur[lettre] += 1
print(dict(compteur))  # {'m':1, 'i':4, 's':4, 'p':2}

# Counter — compter des occurrences
from collections import Counter
mots = ['chat', 'chien', 'chat', 'oiseau', 'chat']
print(Counter(mots))   # Counter({'chat': 3, 'chien': 1, ...})

# Capturer une erreur
try:
    x = int(input('Entrez un nombre : '))
    print(10 / x)
except ValueError:
    print('Ce n est pas un nombre !')
except ZeroDivisionError:
    print('Division par zéro impossible !')

# Capturer n'importe quelle erreur (déconseillé en production)
try:
    resultat = 1 / 0
except Exception as e:
    print(f'Erreur : {e}')

# finally : s'exécute toujours (erreur ou pas)
try:
    f = open('fichier.txt', 'r')
    contenu = f.read()
except FileNotFoundError:
    print('Fichier introuvable')
else:
    print('Lecture réussie :', contenu)  # si pas d erreur
finally:
    print('Fin de la tentative')  # toujours exécuté

# Bonne pratique : utiliser with (ferme automatiquement)
try:
    with open('fichier.txt', 'r') as f:
        contenu = f.read()
except FileNotFoundError:
    print('Fichier introuvable')

class Animal:
    def __init__(self, nom):
        self.nom = nom

    def parler(self):
        print(f'{self.nom} fait du bruit.')

# Classe enfant qui hérite de Animal
class Chien(Animal):
    def parler(self):  # redéfinit la méthode
        print(f'{self.nom} dit : Ouaf !')

class Chat(Animal):
    def __init__(self, nom, couleur):
        super().__init__(nom)  # appelle __init__ du parent
        self.couleur = couleur

    def parler(self):
        print(f'{self.nom} dit : Miaou !')

rex = Chien('Rex')
rex.parler()      # Rex dit : Ouaf !

minou = Chat('Minou', 'noir')
minou.parler()    # Minou dit : Miaou !

class Cercle:
    def __init__(self, rayon):
        self._rayon = rayon  # _ = conventionnellement 'privé'

    @property
    def rayon(self):
        return self._rayon

    @rayon.setter
    def rayon(self, valeur):
        if valeur < 0:
            raise ValueError('Le rayon ne peut pas être négatif')
        self._rayon = valeur

    @property
    def aire(self):
        import math
        return math.pi * self._rayon ** 2

    def __repr__(self):
        return f'Cercle(rayon={self._rayon})'

    def __eq__(self, autre):
        return self._rayon == autre._rayon

c = Cercle(5)
print(c.aire)    # 78.53...
print(c)         # Cercle(rayon=5)
c.rayon = 10     # passe par le setter
c.rayon = -1     # ValueError !
